$path = "D:\이력서\AVEVA - Marine Principal Technical Support & Consultant – PLM SME, Busan\Proposal\Future_Industrial_PLM_Meeting_Deck_EN_V5.pptx"
$ppt = New-Object -ComObject PowerPoint.Application
try {
    $pres = $ppt.Presentations.Open($path, $true, $false, $false)  # ReadOnly, Untitled, WithWindow=false
    Write-Output "SLIDE COUNT: $($pres.Slides.Count)"
    foreach ($slide in $pres.Slides) {
        Write-Output "`n===== SLIDE $($slide.SlideIndex) ====="
        foreach ($shape in $slide.Shapes) {
            if ($shape.HasTextFrame -eq -1 -and $shape.TextFrame.HasText -eq -1) {
                $t = $shape.TextFrame.TextRange.Text
                if (-not [string]::IsNullOrWhiteSpace($t)) {
                    Write-Output ("[" + $shape.Name + "] " + ($t -replace "\r"," | "))
                }
            }
        }
    }
    $pres.Close()
} finally {
    $ppt.Quit()
    [System.Runtime.InteropServices.Marshal]::ReleaseComObject($ppt) | Out-Null
}

$dirs = @("$env:USERPROFILE\Downloads", "D:\이력서\AVEVA - Marine Principal Technical Support – Consultant – PLM SME, Busan", "D:\이력서\AVEVA - Marine Principal Technical Support & Consultant – PLM SME, Busan", "$env:USERPROFILE\Pictures", "$env:USERPROFILE\Desktop")
foreach ($d in $dirs) {
  if (Test-Path $d) {
    Get-ChildItem -Path $d -Recurse -Include *.png,*.jpg,*.jpeg -ErrorAction SilentlyContinue |
      Where-Object { $_.LastWriteTime -gt (Get-Date).AddDays(-7) } |
      Sort-Object LastWriteTime -Descending | Select-Object -First 20 FullName, LastWriteTime, Length
  }
}
